import { useQuery } from '@tanstack/react-query';
import React from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';

const Search = () => {
  const serachTerm= useParams();

  const {isLoading,isError,error,data:searched}=useQuery({
    queryKey:['searched'],
    queryFn: ()=> fetchSearch(`${serachTerm}`)
    .then((result)=> result),
  })
  return (
    <section className='search'>
      <div>
        <img src={searched && `${Img_URL}${searched.poster_path}`} alt="" />
      </div>
    </section>
  )
}

export default Search
